+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelation } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { World } from '../world';
+
+export const $aspect = Symbol('aspect');
+
+let aspectId = 0;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+};
+
+type AspectInput = Trait | Aspect;
+type Records<T extends readonly Trait[]> = T[number] extends Trait ? TraitRecord<T[number]> : never;
+
+export function createAspect<T extends readonly [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<FlattenTraits<T>> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (trait[$internal].relation || isRelation(trait)) {
+            throw new Error('Aspects cannot contain relations');
+        }
+        const traitSchema = trait.schema;
+        if (typeof traitSchema === 'function') continue;
+        for (const key of Object.keys(traitSchema)) {
+            if (fields.has(key)) throw new Error(`Aspect field "${key}" is defined by more than one trait`);
+            fields.add(key);
+            schema[key] = traitSchema[key];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits, schema }) as Aspect<FlattenTraits<T>>;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect<T extends Aspect>(world: World, entity: Entity, aspect: T): Records<T['traits']> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(result, getTrait(world, entity, trait));
+    return result as Records<T['traits']>;
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>) {
+    for (const trait of aspect.traits) {
+        const part = pickTraitFields(trait, value);
+        if (Object.keys(part).length) setTrait(world, entity, trait, part);
+    }
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value?: Record<string, unknown>) {
+    const configs: ConfigurableTrait[] = [];
+    for (const trait of aspect.traits) {
+        if (hasTrait(world, entity, trait)) continue;
+        const part = value && pickTraitFields(trait, value);
+        configs.push(part && Object.keys(part).length ? [trait, part] : trait);
+    }
+    addTrait(world, entity, ...configs);
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+function pickTraitFields(trait: Trait, value: Record<string, unknown>): Record<string, unknown> {
+    const schema = trait.schema;
+    if (typeof schema === 'function') return value;
+    const result: Record<string, unknown> = {};
+    for (const key of Object.keys(schema)) if (key in value) result[key] = value[key];
+    return result;
+}
+
+type FlattenTrait<T> = T extends Aspect<infer U> ? U[number] : T extends Trait ? T : never;
+export type FlattenTraits<T extends readonly AspectInput[]> = { [K in keyof T]: FlattenTrait<T[K]> } extends infer U
+    ? U extends readonly Trait[]
+        ? U
+        : never
+    : never;
