+function getDataSlots(params: QueryParameter[]): (Trait | Aspect)[] {
+    const slots: (Trait | Aspect)[] = [];
+    for (const param of params) {
+        if (isAspect(param)) slots.push(param);
+        else if (isModifier(param) && param.type !== 'not') {
